CREATE TABLE `PrivateContentImport` (`id` VARCHAR(191) NOT NULL, `packageId` VARCHAR(191) NOT NULL, `packageRevision` INTEGER NOT NULL, `packageSha256` CHAR(64) NOT NULL, `planSha256` CHAR(64) NOT NULL, `status` VARCHAR(32) NOT NULL, `ownerActorId` VARCHAR(191) NULL, `sourceTaleId` VARCHAR(191) NULL, `contentJson` LONGTEXT NOT NULL, `importedTaleIds` LONGTEXT NOT NULL, `importedAssetIds` LONGTEXT NOT NULL, `warnings` LONGTEXT NOT NULL, `correlationId` VARCHAR(191) NOT NULL, `finalizationErrorCode` VARCHAR(191) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `completedAt` DATETIME(3) NULL, UNIQUE INDEX `PrivateContentImport_packageSha256_key`(`packageSha256`), UNIQUE INDEX `PrivateContentImport_packageId_packageRevision_key`(`packageId`, `packageRevision`), INDEX `PrivateContentImport_status_createdAt_idx`(`status`, `createdAt`), PRIMARY KEY (`id`));
CREATE TABLE `PrivateContentImportMapping` (`id` VARCHAR(191) NOT NULL, `importId` VARCHAR(191) NOT NULL, `sourceLogicalId` VARCHAR(191) NOT NULL, `targetId` VARCHAR(191) NOT NULL, `kind` VARCHAR(64) NOT NULL, UNIQUE INDEX `PrivateContentImportMapping_importId_sourceLogicalId_key`(`importId`, `sourceLogicalId`), PRIMARY KEY (`id`), CONSTRAINT `PrivateContentImportMapping_importId_fkey` FOREIGN KEY (`importId`) REFERENCES `PrivateContentImport`(`id`) ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE `PrivateAssetObject` (`id` VARCHAR(191) NOT NULL, `sha256` CHAR(64) NOT NULL, `byteLength` INTEGER NOT NULL, `mediaType` VARCHAR(191) NOT NULL, `representation` VARCHAR(32) NOT NULL, `storageKey` VARCHAR(255) NOT NULL, `finalizedAt` DATETIME(3) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), UNIQUE INDEX `PrivateAssetObject_sha256_key`(`sha256`), UNIQUE INDEX `PrivateAssetObject_storageKey_key`(`storageKey`), PRIMARY KEY (`id`));
CREATE TABLE `PrivateAssetReference` (`id` VARCHAR(191) NOT NULL, `importId` VARCHAR(191) NOT NULL, `objectId` VARCHAR(191) NOT NULL, `logicalId` VARCHAR(191) NOT NULL, `ownerActorId` VARCHAR(191) NULL, `taleId` VARCHAR(191) NULL, `playthroughId` VARCHAR(191) NULL, `visibility` VARCHAR(32) NOT NULL DEFAULT 'PRIVATE', `revealState` VARCHAR(32) NOT NULL DEFAULT 'LOCKED', `available` BOOLEAN NOT NULL DEFAULT false, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), UNIQUE INDEX `PrivateAssetReference_importId_logicalId_key`(`importId`, `logicalId`), INDEX `PrivateAssetReference_playthroughId_revealState_available_idx`(`playthroughId`, `revealState`, `available`), PRIMARY KEY (`id`), CONSTRAINT `PrivateAssetReference_importId_fkey` FOREIGN KEY (`importId`) REFERENCES `PrivateContentImport`(`id`) ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT `PrivateAssetReference_objectId_fkey` FOREIGN KEY (`objectId`) REFERENCES `PrivateAssetObject`(`id`) ON DELETE RESTRICT ON UPDATE CASCADE);
